# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from prometheus_client import start_http_server, Counter
import flask

app = flask.Flask(__name__)
REQUESTS = Counter(
    'http_requests_total',
    'HTTP requests total by user_id, session_id and path',
    ['user_id', 'session_id', 'path']
)

@app.route('/')
def index():
    REQUESTS.labels(user_id='user1', session_id='session123', path='/').inc()
    return "Hello, World!"

@app.route('/api/<int:user_id>/<string:session_id>/<path:path>')
def api(user_id, session_id, path):
    REQUESTS.labels(user_id=user_id, session_id=session_id, path=path).inc()
    return flask.jsonify({'user_id': user_id, 'session_id': session_id, 'path': path})

if __name__ == '__main__':
    start_http_server(8000)
    app.run(host='0.0.0.0')